func (s *DynamicProtoService) validateProtoContent(content string) error {
	lines := strings.Split(content, "\n")
	
	hasSyntax := false
	for _, line := range lines {
		trimmed := strings.TrimSpace(line)
		
		if strings.HasPrefix(trimmed, "syntax") {
			hasSyntax = true
		}
		
		if strings.Contains(trimmed, "import") && !strings.HasPrefix(trimmed, "//") {
			importPath := extractImportPath(trimmed)
			if importPath != "" && !s.allowedImports[importPath] {
				return fmt.Errorf("import not allowed: %s", importPath)
			}
		}
		
		if strings.Contains(trimmed, "exec") || strings.Contains(trimmed, "system") || 
		   strings.Contains(trimmed, "cmd") || strings.Contains(trimmed, "../") {
			return fmt.Errorf("suspicious content detected")
		}
	}

	if !hasSyntax {
		return fmt.Errorf("proto must specify syntax version")
	}

	return nil
}

func extractImportPath(line string) string {
	start := strings.Index(line, "\"")
	if start == -1 {
		return ""
	}
	end := strings.Index(line[start+1:], "\"")
	if end == -1 {
		return ""
	}
	return line[start+1 : start+1+end]
}

func (s *DynamicProtoService) hashProto(content string) string {
	hash := sha256.Sum256([]byte(content))
	return hex.EncodeToString(hash[:])
}

func (s *DynamicProtoService) compileProtoDefinition(hash, content string) (*CompiledProto, error) {
	protoDir := filepath.Join(s.workDir, hash)
	if err := os.MkdirAll(protoDir, 0755); err != nil {
		return nil, fmt.Errorf("failed to create proto directory: %v", err)
	}

	protoPath := filepath.Join(protoDir, "dynamic.proto")
	if err := ioutil.WriteFile(protoPath, []byte(content), 0644); err != nil {
		return nil, fmt.Errorf("failed to write proto file: %v", err)
	}

	descriptorPath := filepath.Join(protoDir, "descriptor.pb")

	cmd := exec.Command("protoc",
		"--proto_path="+protoDir,
		"--descriptor_set_out="+descriptorPath,
		"--include_imports",
		protoPath,
	)

	output, err := cmd.CombinedOutput()
	if err != nil {
		os.RemoveAll(protoDir)
		return nil, fmt.Errorf("protoc compilation failed: %v, output: %s", err, string(output))
	}

	if _, err := os.Stat(descriptorPath); os.IsNotExist(err) {
		os.RemoveAll(protoDir)
		return nil, fmt.Errorf("descriptor file not generated")
	}

	return &CompiledProto{
		Hash:           hash,
		DescriptorPath: descriptorPath,
		ProtoPath:      protoPath,
	}, nil
}

